import { useEffect, useState } from 'react';
import api from '../lib/api';
import { formatDate } from '../lib/utils';
import './Social.css';

const TWITTER_HANDLE = '_TheRead1';

const XIcon = () => (
  <svg viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
    <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-4.714-6.231-5.401 6.231H2.748l7.73-8.835L1.254 2.25H8.08l4.259 5.63zm-1.161 17.52h1.833L7.084 4.126H5.117z"/>
  </svg>
);

function TweetCard({ tweet }) {
  const url = `https://twitter.com/${tweet.author?.username}/status/${tweet.id}`;
  const metrics = tweet.public_metrics || {};

  // Convert URLs in text to clickable links and clean up t.co links
  const renderText = (text, entities) => {
    if (!entities?.urls?.length) return text;
    let result = text;
    // Remove trailing t.co URLs (media links)
    entities.urls.forEach(u => {
      if (u.images || u.media_key) {
        result = result.replace(u.url, '');
      } else {
        result = result.replace(u.url, u.display_url || u.url);
      }
    });
    return result.trim();
  };

  return (
    <a
      href={url}
      target="_blank"
      rel="noopener noreferrer"
      className="tweet-card glass"
    >
      {/* Author */}
      <div className="tweet-card__author">
        {tweet.author?.profile_image_url && (
          <img src={tweet.author.profile_image_url} alt={tweet.author.name} className="tweet-card__avatar" />
        )}
        <div>
          <p className="tweet-card__name">{tweet.author?.name}</p>
          <p className="tweet-card__handle">@{tweet.author?.username}</p>
        </div>
        <div className="tweet-card__x-icon"><XIcon /></div>
      </div>

      {/* Text */}
      <p className="tweet-card__text">
        {renderText(tweet.text, tweet.entities)}
      </p>

      {/* Media */}
      {tweet.media?.length > 0 && tweet.media[0].type === 'photo' && (
        <div className="tweet-card__media">
          <img src={tweet.media[0].url} alt="Tweet media" />
        </div>
      )}

      {/* Footer */}
      <div className="tweet-card__footer">
        <span className="tweet-card__date">{formatDate(tweet.created_at)}</span>
        <div className="tweet-card__metrics">
          {metrics.reply_count > 0 && (
            <span>💬 {metrics.reply_count}</span>
          )}
          {metrics.retweet_count > 0 && (
            <span>🔁 {metrics.retweet_count}</span>
          )}
          {metrics.like_count > 0 && (
            <span>♥ {metrics.like_count}</span>
          )}
        </div>
      </div>
    </a>
  );
}

export default function Social() {
  const [tweets, setTweets] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);

  useEffect(() => {
    api.get('/tweets')
      .then(({ data }) => {
        if (data.tweets?.length) setTweets(data.tweets);
        else setError(true);
      })
      .catch(() => setError(true))
      .finally(() => setLoading(false));
  }, []);

  return (
    <main className="social-page">
      <section className="social-page__hero section">
        <div className="container">
          <p className="caption fade-up">Social</p>
          <h1 className="heading-1 fade-up-1">Thoughts from the Field</h1>
          <p className="body-lg fade-up-2" style={{ color: 'var(--text-secondary)', maxWidth: 500, marginTop: 12 }}>
            Quick updates, research threads, and field observations from{' '}
            <a href={`https://twitter.com/${TWITTER_HANDLE}`} target="_blank" rel="noopener noreferrer" style={{ color: 'var(--accent)' }}>
              @{TWITTER_HANDLE}
            </a>.
          </p>
        </div>
      </section>

      <section className="section" style={{ paddingTop: 0 }}>
        <div className="container">
          <div className="social-page__grid fade-up-1">

            {/* Feed */}
            <div>
              {loading ? (
                <div className="tweets-grid">
                  {[1,2,3,4,5,6].map(i => (
                    <div key={i} className="tweet-skeleton glass">
                      <div style={{ display: 'flex', gap: 10, marginBottom: 12 }}>
                        <div className="skeleton" style={{ width: 40, height: 40, borderRadius: '50%', flexShrink: 0 }} />
                        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 6 }}>
                          <div className="skeleton" style={{ height: 12, width: '50%' }} />
                          <div className="skeleton" style={{ height: 10, width: '30%' }} />
                        </div>
                      </div>
                      <div className="skeleton" style={{ height: 13, width: '100%', marginBottom: 6 }} />
                      <div className="skeleton" style={{ height: 13, width: '80%' }} />
                    </div>
                  ))}
                </div>
              ) : error || tweets.length === 0 ? (
                <div className="social-page__fallback glass">
                  <div className="social-page__fallback-icon">
                    <XIcon />
                  </div>
                  <p className="body" style={{ fontWeight: 500 }}>@{TWITTER_HANDLE}</p>
                  <p className="body-sm" style={{ color: 'var(--text-secondary)', marginTop: 8, maxWidth: 300, textAlign: 'center' }}>
                    Tweets couldn't load right now. Visit the profile directly on X to see the latest posts.
                  </p>
                  <a href={`https://twitter.com/${TWITTER_HANDLE}`} target="_blank" rel="noopener noreferrer" className="btn btn-primary" style={{ marginTop: 20 }}>
                    View on X ↗
                  </a>
                </div>
              ) : (
                <div className="tweets-grid">
                  {tweets.map(tweet => (
                    <TweetCard key={tweet.id} tweet={tweet} />
                  ))}
                </div>
              )}
            </div>

            {/* Sidebar */}
            <div className="social-page__side">
              <div className="glass social-page__info-card">
                <p className="caption" style={{ marginBottom: 12 }}>About</p>
                <p className="body-sm" style={{ color: 'var(--text-secondary)', lineHeight: 1.7 }}>
                  Follow along for field updates, research threads, and thoughts on wood science, forestry, and sustainable construction.
                </p>
                <a href={`https://twitter.com/${TWITTER_HANDLE}`} target="_blank" rel="noopener noreferrer"
